"""
mkt-original | deuteronomy | ch14–17 fill
present: ch14:v2,21; ch15:v1,11; ch16:v1,20; ch17:v6,18 — 86 missing
run: python3 scripts/zc-original-deuteronomy-14-17-fill.py

Key term decisions:
- YHWH retained as divine name in commentary
- shemittah = release (ch15); ma'aser = tithe (ch14)
- kashrut = the purity/clean-food system; parash/gerah as the key criteria
- Law of the King (17:14-20): most politically significant passage for OT monarchy theology
"""

import json, pathlib

ROOT = pathlib.Path(__file__).resolve().parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        existing.setdefault(ch, {})
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DEUT = {
  "14": {
    "1": "<p><strong>banim atem laYHWH Eloheichem</strong>: 'You are children (<em>bānîm</em>) of the LORD your God.' The familial designation opens the purity laws: the food restrictions are grounded not in hygiene or arbitrary rules but in Israel's identity as YHWH's children (<em>bānîm</em>). The father-son relationship with YHWH is a Deuteronomic theme (1:31; 8:5; 32:6) that the NT applies to believers — 'you are all sons of God through faith' (Gal 3:26). The mourning-rites prohibited (<em>titgodedu</em>, gashing yourselves; <em>shim tusumu qorcha</em>, shaving the front of the head for the dead) are Egyptian and Canaanite funerary practices that blurred the boundary between Israel and surrounding nations. The prohibition grounds: if you are YHWH's children, you do not mourn as those who have no covenant hope.</p>",
    "3": "<p><strong>lo-tokhal kol-toeva</strong>: 'You shall not eat any detestable thing (<em>tôʿēḇāh</em>).' The single summary verse before the purity-list uses <em>tôʿēḇāh</em> (abomination, detestable thing) — the strongest category of violation in Deuteronomy's ethical vocabulary. The same word covers idolatry (7:25-26; 13:15), sexual prohibitions (Lev 18:22,26-30), and unjust business practices (25:16). By leading the food-law section with this term, Deuteronomy frames dietary practice not as mere etiquette but as a matter of covenantal integrity: eating the wrong foods is categorically as serious as other covenant violations. The NT's Peter-Cornelius vision (Acts 10:14-15) directly addresses this <em>tôʿēḇāh</em> framework: 'What God has made clean, do not call common.'</p>",
    "4": "<p><strong>zot habehemah asher tokhelon</strong>: 'These are the animals you may eat: the ox, the sheep, and the goat.' The permitted animal list begins with the three domestic herd/flock animals — <em>shor</em> (ox), <em>seh kesavim</em> (sheep), <em>seh izzim</em> (goat) — the primary sacrificial and food animals. Their permissibility is not incidental; these are the very animals used in sacrifice (Lev 1-5), establishing a structural connection between what Israel eats and what Israel offers: the animals that may be eaten are the animals that may be offered. The dietary laws and the sacrificial laws share the same list.</p>",
    "5": "<p><strong>ha'ayyel vehatzvi vehayyachmur veha'aqqo vehadishon uteho vezamer</strong>: 'the deer, the gazelle, the roe deer, the wild goat, the ibex, the antelope, and the mountain sheep.' The list of wild game expands the permitted category to seven named species. Several of these are hapax legomena whose precise identification is uncertain (cf. the variety in English translations): <em>yaḥmûr</em> (roe deer or fallow deer), <em>ʾaqqô</em> (ibex?), <em>dišôn</em> (antelope?), <em>tᵉô</em> (wild ox?), <em>zemer</em> (mountain sheep? chamois?). The naming of seven species (a complete-number list) suggests the permission is comprehensive: all split-hooved, cud-chewing wild game is clean. The LXX's identification of these animals follows Hellenistic zoological categories rather than precise species correspondence.</p>",
    "6": "<p><strong>vekhol behemah maphresat parsa shosa sheti ferasot maalat gerah</strong>: 'You may eat any animal that has completely split hooves and chews the cud.' The two-criteria system for clean land animals — <em>pārāsāh</em> (hoof) that is both <em>maphresat</em> (split, cleft) and <em>šôsaʿat</em> (completely split into two halves) plus <em>maʿălat gērāh</em> (brings up the cud, ruminates) — must both be present for an animal to be clean. The dual requirement prevents misidentification by single-criterion matching: the camel chews the cud but lacks the split hoof; the pig has the hoof but does not chew the cud. The Levitical parallel (Lev 11:2-8) is slightly fuller; Deuteronomy's summary form assumes the reader knows the Levitical tradition.</p>",
    "7": "<p><strong>akh et-zeh lo tokhelon mimaalei hagerah umimmiphrisei haperisah hashesuyah</strong>: 'However, among those that chew the cud or have split hooves, these you shall not eat: the camel, the hare, and the rock badger.' The three borderline cases — <em>gamal</em> (camel), <em>arnevet</em> (hare), <em>shaphān</em> (rock badger/hyrax) — are animals that appear to meet one criterion but not the other. <em>ki maʿaleh gerah hemmah ufarsah lo hiprisu</em> (for they chew the cud but do not divide the hoof): the hare and rock badger are not true ruminants in modern taxonomy, but their chewing motion (grinding molars, caecotrophy in rabbits) presented as cud-chewing to ancient observers. The classification is phenomenological — based on observable behavior — rather than anatomical.</p>",
    "8": "<p><strong>ve'et-haḥazir ki-maphris parsa hu velo yigar gerah tame hu lachem</strong>: 'And the pig — though it has split hooves, it does not chew the cud. It is unclean for you.' The pig (<em>ḥăzîr</em>) is mentioned last and with extra emphasis, perhaps because of its particular status in Canaanite and later Hellenistic culture. The pig's single-criterion status (hooves yes, cud no) makes it the paradigmatic unclean animal. In the Maccabean period (1 Macc 1:47-63; 2 Macc 6:18-7:42), forced pork consumption became the test-case for apostasy: refusing to eat pork was the defining act of Jewish identity maintenance under Antiochus IV. The pig-prohibition thus carried historical-martyrdom weight beyond its textual origin.</p>",
    "9": "<p><strong>et-zeh tokhelon mikol asher bamayim kol-asher lo senapir vesquamah tokhelon</strong>: 'Of all creatures living in the water, you may eat those that have fins and scales.' The two criteria for clean aquatic life — <em>sᵉnappîr</em> (fins) and <em>qasqeset</em> (scales) — are simpler than the land-animal criteria. The positive formulation first ('you may eat whatever has fins and scales') before the negative prohibition makes the clean category the baseline. The criteria effectively permit fish and some shellfish while excluding others — but the precise scope is debated because ancient Israelite taxonomic knowledge of aquatic life was less developed than their knowledge of land animals.</p>",
    "10": "<p><strong>vekhol asher ein lo senapir vesquamah lo tokhelon tame hu lachem</strong>: 'But whatever lacks fins or scales you shall not eat; it is unclean for you.' The negation of both criteria prohibits shellfish, crustaceans, eels, and catfish. <em>ṭāmēʾ hûʾ lākem</em> (it is unclean for you) — the personal pronoun <em>lākem</em> (for you) is significant: the uncleanness is relational, not absolute. The animal is not intrinsically corrupt; it is unsuitable for Israel because of Israel's covenant status as a holy people. The NT's 'clean all foods' declaration (Mark 7:19; Acts 10:15; Rom 14:14) removes the <em>lākem</em> restriction by extending the covenant community beyond ethnic Israel.</p>",
    "11": "<p><strong>kol-tzippor tehorah tokhelon</strong>: 'You may eat any clean bird.' The positive statement for birds is brief because the list immediately follows with the prohibited species (vv. 12-18). The clean-bird category is defined by exclusion rather than positive criteria. The absence of anatomical criteria for birds (unlike the hoof/cud system for land animals) suggests that identification relied on traditional knowledge and specific prohibitory lists rather than a systematic rule. The Mishnaic tractate Hullin develops a four-sign system for birds (crops, extra toe, peelable gizzard, egg-catching behavior), but this is later rabbinic development.</p>",
    "12": "<p><strong>ve'elleh asher lo tokhelon mehem hannesher vehaperes veha'ozniyyah</strong>: 'These are the birds you shall not eat: the eagle, the bearded vulture (<em>peres</em>), and the black vulture (<em>ʾozniyyāh</em>).' The prohibited bird list begins with the large raptors — <em>nesher</em> (eagle or griffon vulture), <em>peres</em> (bearded vulture/lammergeier), <em>ʾozniyyāh</em> (black vulture or osprey). These are all carrion-feeding or large predatory birds. The ecological principle seems to be that birds of prey that tear and consume blood are unsuitable — consistent with the blood-prohibition that underlies much of the kashrut system.</p>",
    "13": "<p><strong>vehara'ah ve'et-ha'ayya vehadayyah leminam</strong>: 'the kite and any kind of falcon.' <em>rāʾāh</em> (kite), <em>ʾayyāh</em> (falcon or kite species), <em>dayyāh</em> (kite or falcon, Lev 11:14) — the phrase <em>lemînāh</em> (according to its kind) extends each prohibition to all species of the genus. The same extension-phrase (<em>lemîn</em>) is used in Genesis 1's creation account for the multiplication of living creatures according to their kinds — Deuteronomy's food laws use creation-vocabulary to organize the animal world.</p>",
    "14": "<p><strong>ve'et kol-orev lemino</strong>: 'every kind of raven.' The raven (<em>ʿōrēḇ</em>) is prohibited with its entire genus (<em>lᵉmînô</em>). Ravens and crows are omnivores that feed on carrion — consistent with the predator/carrion-feeder pattern of the prohibited bird list. The raven appears in biblical narrative at significant moments: sent out by Noah from the ark (Gen 8:7) and feeding Elijah at the brook Cherith (1 Kgs 17:6) — a divine use of an unclean bird for a clean purpose, demonstrating YHWH's sovereign freedom over the categories he has established.</p>",
    "15": "<p><strong>ve'et-ha'astityah vehat-tes vehashahal ve'et-hanets leminehu</strong>: 'the ostrich, the nighthawk, the sea gull, and every kind of hawk.' The <em>bat-yaʿănāh</em> (ostrich, literally 'daughter of howling' or 'daughter of greed') appears in Lev 11:16 as well. The ostrich's inclusion in the prohibited list is consistent with its behavior as a scavenger and its consumption of various non-food materials. The <em>lemîn</em> extension again covers all species of each type, making the prohibitory list comprehensive across genera.</p>",
    "16": "<p><strong>ha-kos vehashalakh vehayanshup</strong>: 'the little owl, the screech owl, and the barn owl.' The three owl species (precise identifications uncertain — <em>kôs</em>, <em>šālaḵ</em>, <em>yansûp</em>) are nocturnal predators. The owl's association with desolation and ruins in the prophets (Isa 34:11,13-15; Jer 50:39; Zeph 2:14) may reflect its status as an unclean bird dwelling in destroyed places — a habitat that symbolizes divine judgment. The banned birds tend to be associated with death (carrion-feeders), predatory violence (raptors), or desolation (owls).</p>",
    "17": "<p><strong>vehaqa'at ve'et-harakham ve'et-hashalaḵ</strong>: 'the pelican, the carrion vulture (<em>rāhām</em>), and the cormorant (<em>šālaḵ</em>).' <em>qāʾāt</em> (pelican or owl species), <em>rāhām</em> (osprey or Egyptian vulture — related to <em>raḥam</em>, compassion/love, an ironic bird-name), <em>šālaḵ</em> (gannet or cormorant). These are aquatic birds that pursue fish rather than live on land — adding a dimension to the prohibited birds: not only carrion-feeders and raptors but fish-eating water-birds are also excluded. The fish-catching birds stand at the intersection of clean aquatic prey and unclean bird predation.</p>",
    "18": "<p><strong>vehaḥasidah veha'anafah lemina vehadukiphath vehaat'alleph</strong>: 'the stork, any kind of heron, the hoopoe, and the bat.' <em>ḥăsîdāh</em> (stork) — the name derives from <em>ḥesed</em> (steadfast love/kindness), perhaps because storks were observed caring attentively for their young. The irony that the <em>ḥăsîdāh</em> (kindness-bird) is unclean was noticed in rabbinic literature (b. Hullin 63a). <em>ʿăṭallēp</em> (bat) — the bat is technically a mammal but classified with the birds in the ancient taxonomy (as in Lev 11:19); it concludes the bird list with the most anomalous creature, one that flies but has no feathers.</p>",
    "19": "<p><strong>vekhol-shretz ha'of tame hu lachem lo ye'akhelu</strong>: 'All winged insects (<em>šereṣ hāʿôp</em>) are unclean for you; they shall not be eaten.' The <em>šereṣ</em> category (swarming creatures) covers insects and small flying creatures generally. Leviticus 11:20-23 qualifies this: winged insects that go on all fours are unclean, but those with jointed legs for leaping (locusts, crickets, grasshoppers) are clean. Deuteronomy's summary form does not include the locust exception, which is assumed from the Levitical tradition. John the Baptist's diet of locusts and wild honey (Matt 3:4; Mark 1:6) was fully within the permitted-insect exception, placing him squarely within Israel's kashrut framework.</p>",
    "20": "<p><strong>kol-of tahor tokhelon</strong>: 'But all clean birds you may eat.' The brief summary permission (echoing v. 11) closes the prohibited-bird section by restating the positive category. The repetition brackets the prohibition list (vv. 11 → prohibited list → v. 20) with positive permission statements — Deuteronomy's rhetorical pattern of sandwiching prohibitions within affirmations of what is allowed, reflecting the covenant's positive framework: the restrictions exist within a broader grant of freedom.</p>",
    "22": "<p><strong>aser teaser et kol-tevuat zarecha hayotzeh hasadeh shana shana</strong>: 'You shall tithe (<em>ʿaśśēr tᵉʿaśśēr</em>) all the yield of your seed that comes from the field each year.' The doubled verb <em>ʿaśśēr tᵉʿaśśēr</em> (tithe you shall tithe) — the Piel infinitive absolute + finite verb — is the Hebrew emphasis construction, indicating the strongest possible obligation: you must certainly tithe. <em>māʿăśēr</em> (tithe, ten-percent) — the practice of giving a tenth to religious institutions has ancient Near Eastern precedent (tribute to temples, to kings). Deuteronomy's tithe is specifically designated for the sanctuary feast at the chosen place, with provision for the Levite (v. 27) and the poor every third year (v. 28-29). The system distributes the agricultural surplus through worship and social solidarity.</p>",
    "23": "<p><strong>ve'akhalita lifnei YHWH Eloheicha bemakom asher yivchar leshakem shemo sham</strong>: 'And in the presence of YHWH your God, at the place he will choose to make his name dwell, you shall eat the tithe of your grain, wine, and oil, and the firstborn of your herd and flock.' The tithe is to be eaten in YHWH's presence (<em>lipnê YHWH</em>) — a communal feast before YHWH at the central sanctuary, not merely a tax payment. <em>lᵉmaʿan tilmad lᵉyārᵉʾāh ʾet-YHWH Eloheycha kol-hayyamim</em> (so that you may learn to fear the LORD your God always) — the feast's purpose is formative: annual eating of the tithe at the sanctuary is an annual education in YHWH-fear, a structured liturgical pedagogy that sustains covenant orientation through repeated practice.</p>",
    "24": "<p><strong>vekhiy-yirbeh mimkha haderekh ki lo tukhal se'eto</strong>: 'But if the distance is too great for you to carry the tithe.' The tithe law includes a practical accommodation for distance: if the central sanctuary is too far, the tithe may be converted to money (<em>kesep</em>). This <em>kesef tiqquph</em> (money conversion) provision anticipates the reality of scattered settlement in Canaan after the conquest. The conversion is not a debasement of the requirement but an adaptation: the purpose (feast before YHWH) is maintained; the form (carrying physical produce vs. carrying money and buying at the destination) is adjusted for practical necessity.</p>",
    "25": "<p><strong>venatatah bakkesef vetzarerta hakesef beyadkha</strong>: 'then you shall exchange the tithe for money, and take the money in hand to the place that the LORD your God will choose.' <em>wᵉṣārartā hakkesep bᵉyāḏᵉkā</em> (wrap/tie the money in your hand) — the idiom means to carry money safely bundled. The practical detail — wrap it and take it — grounds the religious obligation in ordinary commercial reality. Deuteronomy consistently moves between the transcendent (YHWH's holiness) and the mundane (practical livestock management, commercial exchange) without embarrassment: the covenant governs all of life, including how to carry money to the festival.</p>",
    "26": "<p><strong>unatata hakesef bekhol asher te'aveh nafshkha babaqar uvatsaon uvayayin uvashekhar</strong>: 'and spend the money for whatever you desire — cattle, sheep, wine, strong drink, or whatever you want — and you shall eat it before YHWH your God and rejoice.' <em>wᵉšāmḥtā ʾattāh ûḇêtekā</em> (you shall rejoice, you and your household) — the tithe feast is explicitly joyful. The permission for <em>šēḵār</em> (strong drink, fermented beverage) — often prohibited or restricted — is here explicitly permitted for the tithe feast. The feast is an expression of YHWH's abundance: eat what you desire, rejoice before YHWH. The NT counterpart is the messianic banquet (Luke 14:15-24; Rev 19:9), the ultimate feast-before-YHWH to which all these communal meals pointed.</p>",
    "27": "<p><strong>vehaLevi asher bishareykha lo ta'azvennu ki ein lo helek venachalah imakh</strong>: 'And do not neglect (<em>lōʾ taʿazĕḇennû</em>) the Levite who lives in your towns, for he has no portion or inheritance among you.' The Levite's landlessness is the structural rationale for the tithe provision. <em>ʾên lô ḥēleq wᵉnaḥălāh ʿimmāk</em> (he has no portion or inheritance with you) — the Levites received no territorial allotment in the Canaan distribution (Num 18:20-24; Deut 18:1-2) because YHWH himself is their inheritance. Their economic sustenance therefore depends on the tithe system. The verb <em>taʿazĕḇ</em> (to abandon, forsake) is a strong term: neglecting the Levite is the covenant equivalent of abandoning a dependent member of the covenant community.</p>",
    "28": "<p><strong>miqqets shalosh shanim totzi et-kol-maʿasar tevuatekha bashanah hahi vehinikhta bishearekha</strong>: 'At the end of every three years you shall bring out all the tithe of your produce from that year and store it within your towns.' The third-year tithe (<em>maʿasar shanim shalosh</em>) — distinct from the regular annual tithe — is stored locally rather than taken to the central sanctuary. This local-storage tithe creates a community welfare reserve, accessible throughout the town for the Levite, the resident alien, the fatherless, and the widow (v. 29). The three-year cycle aligns with the Sabbatical year system (every seventh year there is a full release, ch. 15) and creates a multi-layered provision infrastructure.</p>",
    "29": "<p><strong>uvaa haLevi ki ein lo helek venachalah imakh veha-ger vehayatom vehaalmanah asher bishareykha veakhelu vesaveyu</strong>: 'so that the Levite — who has no portion or inheritance among you — and the resident foreigner, the fatherless, and the widow who are in your towns may come and eat and be satisfied.' The beneficiary list — Levite, <em>gēr</em> (resident alien), <em>yātôm</em> (fatherless), <em>ʾalmānāh</em> (widow) — is Deuteronomy's standard quadruplet of the covenant's economically vulnerable. Their needs are structurally built into the tithe calendar: the provision for the poor is not charity but covenant obligation, scheduled and institutionalized. <em>lᵉmaʿan yᵉḇārᵉkᵉkā YHWH Eloheycha bᵉkol-maʿăśēh yāḏᵉkā ʾăšer taʿăśeh</em> (so that YHWH your God may bless you in all the work of your hands) — generosity to the vulnerable is the condition for YHWH's blessing, making the welfare system a covenant-economic investment, not merely humanitarian sentiment.</p>"
  },
  "15": {
    "2": "<p><strong>wezeh devar hashemittah shamot kol-baal masheh yado asher yashe bere'ehu</strong>: 'And this is how the release (<em>šᵉmiṭṭāh</em>) shall work: every creditor shall cancel (<em>šāmôṭ</em>) what he has lent to his neighbor.' <em>šāmôṭ</em> — the root <em>šāmaṭ</em> (to let drop, release, remit) is the same root used in Exod 23:11 for letting the land lie fallow in the seventh year. The debt-release mirrors the land-sabbath: as the land is released from cultivation every seventh year, so debts are released every seventh year. <em>lo-yigos et-re'ehu ve'et-aḥiv</em> (he must not press his neighbor or his brother) — the prohibition on pressing for payment uses the verb <em>nāgas</em> (to exact, press, drive), the same verb used of Pharaoh's slave-masters pressing Israel in Exodus (Exod 3:7; 5:6,10,13,14). The debt-release laws prevent the recreation of Egyptian bondage within Israel.</p>",
    "3": "<p><strong>et-hanokri tiggos ve'asher yihyeh lekha et-aḥikha tashmet yadekha</strong>: 'You may collect from a foreigner, but whatever your brother owes you, you must release.' The distinction between <em>nokrî</em> (foreigner, non-resident alien) and <em>ʾāḥ</em> (brother, fellow Israelite) is an economic-covenantal distinction: the release operates within the covenant community, not universally. This has generated significant discussion in Jewish ethics about the scope of neighbor-obligation. The NT's expansion — 'Is he not also my neighbor?' (Luke 10:29-37) — challenges the limiting function of the <em>ʾāḥ/nokrî</em> distinction in the parable of the Good Samaritan.</p>",
    "4": "<p><strong>efes ki lo-yihyeh bekha evyon ki-barekh yevarekhkha YHWH be'aretz asher YHWH Eloheicha noten lekha</strong>: 'There need be no poor among you, for the LORD will surely bless you in the land.' <em>efes kî</em> (except that, but) — the phrase introduces not a contradiction to v. 11 ('the poor will never cease,' which Jesus quotes in John 12:8) but a conditional vision: poverty is not structurally necessary in the covenant community if covenant obedience is maintained. The doubled blessing verb <em>bārēk yᵉḇārᵉkekā</em> (YHWH will surely bless you) — the Piel infinitive absolute + Piel finite — is the emphatic assurance of prosperity. The tension between v. 4 (need be no poor) and v. 11 (poor will always exist) is Deuteronomy's realistic covenant pedagogy: the ideal is stated, then the practical reality acknowledged.</p>",
    "5": "<p><strong>raq im-shamo'a tishma bekol YHWH Eloheicha lishmor la'asot et-kol-hamitzvah hazot</strong>: 'if only you carefully obey the voice of the LORD your God, being diligent to keep all this commandment.' The doubled imperative <em>šāmôaʿ tišmaʿ</em> (hear-obey you shall hear-obey) — Hebrew's emphatic construction — qualifies the promise of v. 4: the blessing-prosperity is conditional on covenant faithfulness. <em>šāmar laʿăśôt</em> (guard to do) — the paired verbs of covenant faithfulness: guard (internalize, not forget) and do (implement). Deuteronomy consistently pairs these two verbs because knowledge without practice is covenant failure, and practice without understanding is mere external compliance.</p>",
    "6": "<p><strong>ki-YHWH Eloheicha berakhekha kaasher dibber-lakh</strong>: 'For the LORD your God will bless you as he has promised.' <em>kaʾăšer dibber-lāk</em> (as he has spoken to you) — the blessing is not a new promise but the fulfillment of a prior word; the debt-release and generosity laws are embedded in a covenant where YHWH's promise precedes and underwrites the commands. <em>vehaavet goyim rabbim ve'ata lo tilve</em> (you will lend to many nations but not borrow) — the reversal of debtor-creditor status between Israel and the nations is the economic expression of covenant supremacy: the covenant people, when obedient, become the lenders rather than the borrowers. Paul applies this economic reversal spiritually in Phil 4:19: 'my God will supply every need of yours according to his riches in glory.'</p>",
    "7": "<p><strong>ki-yihyeh vekha evyon me'aḥad aḥeicha be'aḥad she'arekha be'artzekha</strong>: 'If there is a poor person (<em>ʾeḇyôn</em>) among you, one of your brothers, in any of your towns.' <em>ʾeḇyôn</em> (needy, poor) — the specific term for one in want, in contrast to <em>ānî</em> (oppressed/humble-poor) and <em>dal</em> (weak/low). The combination of <em>ʾeḇyôn</em> and <em>ʾāḥ</em> (brother) personalizes the economic obligation: the poor person is not an abstract social problem but your brother, a member of the covenant family. <em>lo-tĕ'ammēṣ ʾet-lᵉḇāḇᵉkā wᵉlōʾ tiqpōṣ ʾet-yāḏᵉkā mēʾāḥîkā hāʾeḇyôn</em> (do not harden your heart or shut your hand against your poor brother) — the double prohibition uses body-part metaphors: the heart-hardening and hand-closing are the emotional and practical failures of covenant solidarity.</p>",
    "8": "<p><strong>ki-phato'ah tiphtaḥ et-yadekha lo</strong>: 'Instead, you shall open your hand wide (<em>pāṯôaḥ tipṯaḥ</em>) to him.' The doubled infinitive absolute + finite verb construction (<em>pāṯôaḥ tipṯaḥ</em> — open wide you shall open wide) is the emphatic contrast to the hand-closing of v. 7. <em>vehaavet taavit lo dei mahsoro asher yehsar lo</em> (and lend him whatever he needs, enough for his lack) — <em>mahsoro</em> (his deficit) specifies that the loan amount is calibrated to need, not to lender-convenience. The open-hand imagery recurs in Ps 145:16 as a description of YHWH himself: 'you open your hand and satisfy the desire of every living thing' — Israel's open-handed generosity to the poor imitates YHWH's own provision-character.</p>",
    "9": "<p><strong>hishamer lekha pen-yihyeh davar im-levavekha veliyyaal</strong>: 'Guard against an unworthy thought in your heart (<em>dāḇār ʿim-lᵉḇāḇᵉkā beliyyāʿal</em>).' <em>beliyyāʿal</em> — the compound term (literally &lsquo;without profit/worth&rsquo;) used for thoroughly wicked or worthless persons and things (cf. 'sons of Belial' in Judges, 1 Samuel, and later used as a name for Satan in 2 Cor 6:15). The thought prohibited here is calculating the approach of the shemittah year as a reason to withhold loans to the poor — using the release law as a cover for refusing generosity. Deuteronomy here commands the regulation of internal motivation, not merely external behavior: the problem is <em>bᵉlibbekā</em> (in your heart), not just in your actions.</p>",
    "10": "<p><strong>naton tittennu lo velo-yera levavekha betitkha lo</strong>: 'Give to him generously (<em>nāṯôn tiṯṯennû lô</em>), and do not be reluctant in your heart when you give.' The doubled verb construction — <em>nāṯôn tiṯṯennû</em> (give you shall give) — insists on both external action and internal attitude: give, and do so without heart-resistance. <em>kî biglal haddāḇār hazzeh yᵉḇārᵉkekā YHWH Eloheycha bᵉkol-maʿăśekā</em> (for because of this the LORD your God will bless you in all your work) — the causal link between generosity and blessing is direct: the blessing flows from the giving, connecting the agrarian economy to covenant faithfulness.</p>",
    "12": "<p><strong>ki-yimmakher lekha aḥikha haivri o haivriyvah va'avadkha shesh shanim</strong>: 'If your brother, a Hebrew man or a Hebrew woman, is sold to you and serves you six years.' The slave-manumission law (vv. 12-18) parallels Exod 21:2-6 with significant Deuteronomic expansions. The inclusion of <em>haʿiḇriyyāh</em> (the Hebrew woman) alongside the Hebrew man is Deuteronomy's egalitarian expansion of Exod 21:2, which applies only to male slaves. The six-year service + seventh-year release mirrors the agricultural sabbatical: as the land rests in the seventh year, so the Hebrew slave is released. The Exodus background is explicit in v. 15: 'you were a slave in Egypt.'</p>",
    "13": "<p><strong>vekhiy-teshalleḥenu ḥofshi me'imakh lo teshalleḥenu reiqam</strong>: 'And when you set him free, you shall not send him away empty-handed (<em>rêqām</em>).' <em>rêqām</em> (empty, without resources) — the same word used of Rachel and Leah's complaint against Laban (Gen 31:42) and of Ruth's return to Bethlehem (Ruth 1:21; 3:17). Israel was sent out from Egypt not empty-handed but with the Egyptians' silver and gold (Exod 12:35-36); so the freed Hebrew slave must not be sent out empty-handed. The Exodus pattern governs the slave-release law: as YHWH enriched Israel at the Exodus, so Israelite masters must enrich their freed slaves.</p>",
    "14": "<p><strong>ha'anet taaniq lo mitzanekha umigornekha umiqqevkha</strong>: 'You shall supply him generously from your flock, your threshing floor, and your winepress.' The three sources — flock, threshing floor (grain), winepress (wine) — represent the complete agricultural produce, the three pillars of ancient Israelite rural economy. <em>ka'asher berakhkha YHWH Eloheicha titten lo</em> (as the LORD your God has blessed you, give to him) — the measure of provision is calibrated to the master's own YHWH-given blessing: the freed slave receives in proportion to the master's prosperity. This divine-gift-flowing-through-human-agent pattern is foundational to the NT's theology of generous giving (2 Cor 9:7-8).</p>",
    "15": "<p><strong>vezakharta ki eved hayita be'eretz mitzraim vayyiphdekhha YHWH Eloheicha</strong>: 'Remember that you were a slave in Egypt, and the LORD your God redeemed you.' The Exodus-memory motivation is Deuteronomy's single most repeated ethical driver: remember your former slavery and act accordingly toward those under you. <em>al-ken anokhi metzavvekha et-haddavar hazeh hayom</em> (that is why I command you this today) — the commandment is rooted in the gospel-narrative. The NT equivalent: 'be kind to one another, tenderhearted, forgiving one another, as God in Christ forgave you' (Eph 4:32) — the remembered experience of redemption is the basis for covenant generosity.</p>",
    "16": "<p><strong>vekhiy-yomar elekha lo etze me'imakh ki ahavkha ve'et-beiteckha ki-tov lo imakh</strong>: 'But if the servant says, I do not want to leave you, because he loves you and your household and is well-off with you.' The voluntary-servitude provision addresses the servant who genuinely prefers continued service to freedom. <em>ki ṭôb lô ʿimmāk</em> (because it is good for him with you) — the master's household has become the servant's family; freedom would mean economic insecurity and social displacement. The option of permanent voluntary servitude (marked by ear-piercing) is not exploitation but an acknowledgment of the covenant household as a genuine community of belonging.</p>",
    "17": "<p><strong>velaqaḥta et-hamartzeaa untatah be'ozno uvadelet</strong>: 'then you shall take an awl and pierce his ear against the door, and he shall be your servant permanently.' The ear-piercing ritual (<em>marṣēaʿ</em>, awl + door + ear) is a liminal act: the servant is symbolically bound to the household at its threshold (the door). <em>wᵉʾap laʾamatkha taʿăśeh-kēn</em> (do likewise for your female servant) — Deuteronomy's extension to the female servant ensures she too has the option of permanent covenant-household membership. The ritual of the pierced ear and door-post may echo the Passover blood on the doorpost: the household marked by YHWH's protection encompasses the servants within it.</p>",
    "18": "<p><strong>lo yiqsheh beeinekha beshalleḥkha oto ḥofshi me'imakh</strong>: 'Do not find it difficult in your eyes when you set him free.' <em>lo yiqšeh bᵉʿênekā</em> (let it not be hard in your eyes) — Deuteronomy frequently addresses the inner resistance of the will: the law is not just about external compliance but about overcoming internal reluctance. <em>ki mišneh sekhir sakhir avadkha shesh shanim</em> (for he has served you six years at half the cost of a hired worker) — the economic argument: six years of Hebrew service at half the rate of a free hired worker means the master has already received good economic value; releasing the servant with a provision-gift is a fair return on an advantageous arrangement.</p>",
    "19": "<p><strong>kol-habbekhor asher yivvaled bibekarkha uvatzankha hazkhar taqddish laYHWH Eloheicha</strong>: 'You shall set apart for YHWH your God every firstborn male born of your herd and your flock.' The firstborn-consecration law (vv. 19-23) is grounded in the Exodus: every firstborn belongs to YHWH because YHWH struck down Egypt's firstborn and spared Israel's (Exod 13:1-2,11-16). <em>lo-ta'avod bevikhor shoreka velo tahoz bivikhor tzaonekha</em> (do not work with the firstborn of your ox or shear the firstborn of your flock) — the firstborn animal is withdrawn from agricultural use: its consecrated status means it may not generate economic value for its owner; it is YHWH's working capital, not the farmer's.</p>",
    "20": "<p><strong>lifnei YHWH Eloheicha tokhelennu shanah veshanah</strong>: 'Year by year you shall eat it before YHWH your God at the place YHWH will choose.' The firstborn-animal feast is annual and communal — eating before YHWH at the central sanctuary. <em>ʾattāh ûḇêtekā</em> (you and your household) — the feast includes the entire family. The annual eating of the consecrated firstborn before YHWH builds the household's covenant memory into the agricultural calendar: each year's new firstborn is both the sacrifice and the feast, consecrating the flock-cycle to YHWH's claim while providing communal celebration.</p>",
    "21": "<p><strong>vekhiy-yihyeh vo mum pisseaḥ o iver kol mum ra lo tizbaḥennu laYHWH Eloheicha</strong>: 'But if it has any defect — if it is lame or blind or has any serious flaw — you do not sacrifice it to YHWH your God.' The defect-prohibition for firstborn sacrifice echoes the Levitical requirement for unblemished sacrifices (Lev 22:17-25). <em>pissēaḥ ô ʿiwwēr kol mûm rāʿ</em> (lame or blind or any serious defect) — the defect categories are physical disqualifications for altar-service. Malachi's polemic (Mal 1:8,13-14) condemns post-exilic Israel for offering defective animals — the standard Deuteronomy established was not maintained. The NT's 'without spot or blemish' language for Christ's sacrifice (1 Pet 1:19; Heb 9:14) invokes this sacrificial standard: the perfect sacrifice achieves what blemished animals could only represent.</p>",
    "23": "<p><strong>akh et-damo lo tokhal al-haaretz tishpekhennu kamayim</strong>: 'Only do not eat its blood; pour it out on the ground like water.' The blood-prohibition — <em>al-hāʾāreṣ tišpᵉkennû kammayim</em> (pour it on the ground like water) — grounds the permission to eat unblemished firstborn animals with the fundamental condition: no blood. The blood is poured out because <em>ki-haddām hu hannepeš</em> (for the blood is the life, Deut 12:23; Lev 17:11,14). The blood-life equation is the theological rationale for all blood-prohibition: to eat blood is to consume life itself, which belongs to YHWH. The Jerusalem Council (Acts 15:20,29) retained the blood-prohibition as one of the four requirements for Gentile believers, reflecting its foundational status.</p>"
  },
  "16": {
    "2": "<p><strong>vezavaḥta pesaḥ laYHWH Eloheicha tzon uvakar bmakom asher yivḥar YHWH</strong>: 'You shall sacrifice the Passover offering to YHWH your God — from the flock or the herd — at the place YHWH will choose.' Deuteronomy's Passover is centralized: unlike the household Passover of Exod 12 (slaughtered by families in their homes), Deuteronomy's version requires the central sanctuary. <em>ṣōʾn ûḇāqār</em> (flock or herd) — Deuteronomy expands the Passover offering beyond Exodus's exclusive lamb requirement to include cattle, accommodating larger congregational celebration at the central shrine. The centralization reflects the covenant's post-conquest form: the scattered household practice of Exodus becomes the national communal feast of Deuteronomy.</p>",
    "3": "<p><strong>lo-tokhal alav ḥametz shivat yamim tokhal alav matzot leḥem oni</strong>: 'You shall eat no leavened bread with it. For seven days you shall eat unleavened bread — the bread of affliction (<em>leḥem ʿōnî</em>).' <em>leḥem ʿōnî</em> (bread of affliction/poverty/suffering) — the unleavened bread is designated as memory-food, recalling Egyptian slavery. <em>ʿōnî</em> connects to <em>ʿānāh</em> (to afflict, humble), the verb used of Egypt's oppression of Israel (Exod 1:11,12; Deut 26:7). Eating the flat, poor-man's bread annually reconnects every generation to the pre-Exodus experience of affliction. The NT's Last Supper uses this unleavened bread of Passover as the vehicle for Jesus's self-identification: 'This is my body' (Matt 26:26), giving the bread of affliction a new meaning — the broken body that absorbs the affliction.</p>",
    "4": "<p><strong>velo yera'eh lekha seor bekol-gevulekha shivat yamim velo yalin min-habasar</strong>: 'No leaven shall be seen anywhere in your territory for seven days; and none of the flesh you sacrifice on the evening of the first day shall remain overnight until morning.' The thoroughness of leaven-removal (<em>wᵉlōʾ yērāʾeh lᵉkā śᵉʾōr bᵉkol-gᵉḇûlᵉkā šiḇʿat yāmîm</em>) signals that the festival's memorial function requires a complete change in the household's material environment. Paul's metaphor of the unleavened community (1 Cor 5:6-8) draws directly on this comprehensive leaven-removal: 'Cleanse out the old leaven... let us keep the feast, not with the old leaven of malice and evil, but with the unleavened bread of sincerity and truth.'</p>",
    "5": "<p><strong>lo tukhal lizboaḥ et-hapesaḥ be'aḥad she'areykha</strong>: 'You may not sacrifice the Passover within any of your towns that YHWH your God is giving you.' The repeated prohibition of local sacrifice (following the centralization principle of ch. 12) applies explicitly to the Passover. In Exodus, the Passover was definitionally a household affair; Deuteronomy's transformation of it into a pilgrimage festival (<em>ḥag</em>) is one of the most significant legal-liturgical developments in the Pentateuch. The centralization is not a restriction of piety but an expansion: the household meal becomes the national gathering, the local memorial becomes the pan-Israel covenant renewal.</p>",
    "6": "<p><strong>ki im el-hamakom asher yivḥar YHWH Eloheicha leshaken shemo sham tizbah et-hapesaḥ</strong>: 'Rather, at the place YHWH your God will choose to make his name dwell, there you shall sacrifice the Passover.' <em>lᵉšakkēn šᵉmô šām</em> (to make his name dwell there) — the name-theology again: YHWH's presence is mediated through the name, not through physical residence. <em>ba'erev keḇo' hashemesh</em> (in the evening at sunset) — the timing preserves the original Passover chronology (Exod 12:6: &lsquo;between the evenings&rsquo;). The evening timing creates a nocturnal feast-memorial, connecting the darkness of the original Egyptian night when the destroyer passed over with the annual darkness of communal memorial.</p>",
    "7": "<p><strong>uḇishalta ve'akhaleta bamakom asher yivḥar YHWH Eloheicha bo</strong>: 'You shall cook and eat it at the place YHWH your God will choose, and in the morning you shall return to your tents.' <em>ubashalta veakhaleta</em> (you shall cook and eat) — contrast with Exod 12:8-9's prohibition against boiling: the Exodus Passover was roasted; Deuteronomy permits boiling. This apparent contradiction was resolved in 2 Chr 35:13 ('they roasted the Passover lambs with fire as prescribed, and they boiled the holy offerings in pots') by distinguishing the lamb (roasted) from accompanying offerings (boiled). <em>ûḇabbōqer wᵉpānîtā wᵉhālaḵtā lᵉʾohāleḵā</em> (in the morning you shall return to your tents) — the overnight-to-morning feast structure mirrors the original Passover night.</p>",
    "8": "<p><strong>sheshet yamim tokhal matzot uvayyom hashevii atzeret laYHWH Eloheicha</strong>: 'For six days you shall eat unleavened bread, and on the seventh day there shall be a solemn assembly (<em>ʿăṣeret</em>) for YHWH your God.' <em>ʿăṣeret</em> (solemn assembly, assembly of restraint) — from <em>ʿāṣar</em> (to restrain, hold back): a day of stopping, of gathering for the purpose of assembly. The same term designates the eighth day of Sukkot (Lev 23:36; Num 29:35) and the closing assembly of Shavuot. The seventh-day assembly gives the seven-day Passover/Unleavened Bread festival a Sabbath-like closure: it ends with a day of cessation and gathering before YHWH, structuring the festival in the Sabbath pattern.</p>",
    "9": "<p><strong>shivah shavuot tispor-lakh</strong>: 'Count off seven weeks.' The counting of seven weeks (seven times seven days = forty-nine days) from the beginning of harvest inaugurates the second major festival, Shavuot (Feast of Weeks, Pentecost). The agricultural trigger — <em>meḥel ḥermesh baqqamah</em> (when the sickle is first put to the standing grain) — roots the festival in the harvest cycle: Shavuot celebrates the completion of the grain harvest that began at Passover. The counting itself (<em>tispor-lakh</em>, count for yourself) is a personal obligation, not just a calendar observation; the individual's act of counting participates in the communal memorial.</p>",
    "10": "<p><strong>ve'asita ḥag shavuot laYHWH Eloheicha middat nedavat yadkha</strong>: 'Then you shall celebrate the Feast of Weeks to YHWH your God with a freewill offering (<em>nedāḇāh</em>) from your hand.' <em>mîddat nidaḇat yāḏᵉkā</em> (in proportion to the freewill offering of your hand) — the Shavuot contribution is calibrated to the giver's capacity, not fixed at a set amount. The <em>nedāḇāh</em> (freewill offering) is the opposite of a compelled tax; it is the worshipper's voluntary response to YHWH's blessing. <em>kaʾăšer yᵉḇārᵉkekā YHWH Eloheycha</em> (as YHWH your God has blessed you) — the amount is determined by what YHWH has given, not by external obligation. The NT applies this proportionality principle to financial giving (2 Cor 9:7: 'each one must give as he has decided in his heart, not reluctantly or under compulsion').</p>",
    "11": "<p><strong>vesamaḥta lifnei YHWH Eloheicha atah uvinekha uvittekha ve'avdekha va'amatkha vehallevi</strong>: 'You shall rejoice before YHWH your God — you, your son and daughter, your male and female servants, the Levite, the resident alien, the fatherless, and the widow.' The inclusion list for the Shavuot rejoicing is Deuteronomy's most comprehensive social gathering: the household (you, sons, daughters), the servants (male and female), the landless religious (Levite), and the three categories of the vulnerable (resident alien, fatherless, widow). <em>vesamaḥta</em> (you shall rejoice) is a command, not merely permission: joy before YHWH is a covenant obligation, not an optional emotional response. The festival's shared rejoicing enacts the covenant community's equality before YHWH.</p>",
    "12": "<p><strong>vezakarta ki-eved hayita beMitzrayim veshomarta vaasita et-hakhukkim ha'eleh</strong>: 'Remember that you were a slave in Egypt, and be careful to observe these statutes.' The Exodus-memory motivation reappears for Shavuot. The memory of Egyptian slavery is the motivational foundation for the inclusive festival: because Israel was once enslaved and excluded, its festivals must include every vulnerable person. The covenant community's ethic of inclusion is grounded in the narrative of redemption from exclusion. Later Judaism associated Shavuot with the giving of Torah at Sinai, and the NT's Pentecost (Acts 2) — on the day of Shavuot — frames the Spirit-giving as the new Torah-writing (Jer 31:33; 2 Cor 3:3).</p>",
    "13": "<p><strong>ḥag hassukkot ta'aseh lekha shivat yamim be'aspekha migornekha umiyiqvekha</strong>: 'You shall celebrate the Feast of Booths (<em>ḥag hassûkkôt</em>) for seven days, when you have gathered in the produce from your threshing floor and your winepress.' Sukkot is the third and most joyful pilgrimage festival, celebrating the autumn harvest's completion. <em>mi-gārnᵉkā ûmi-yiqᵉḇkā</em> (from your threshing floor and your winepress) — the final grain and wine harvest is gathered before the festival; Sukkot is the culmination of the agricultural year. The festival's booth-dwelling (<em>sukkāh</em>) recalls Israel's wilderness journey (Lev 23:42-43): the temporary shelters ground the harvest celebration in the memory of dependence on YHWH during the desert years.</p>",
    "14": "<p><strong>vesamaḥta beḥaggekha atah uvinekha uvittekha ve'avdekha va'amatkha vehallevi veha-ger vehayatom veha'almana</strong>: 'You shall rejoice in your feast — you, your son and daughter, your male and female servants, the Levite, the resident alien, the fatherless, and the widow.' The sevenfold inclusion-list (the same as v. 11 for Shavuot) is repeated for Sukkot, emphasizing that the harvest celebration's fullness is measured by its comprehensiveness. <em>vesamaḥta</em> (you shall rejoice) — joy as covenant command: the harvest celebration that excludes any of these groups is incomplete, whatever its external magnificence. Jesus's parable of the great banquet (Luke 14:21-23) echoes this inclusive-feast logic.</p>",
    "15": "<p><strong>shivat yamim taḥog laYHWH Eloheicha bamakom asher yivḥar YHWH</strong>: 'For seven days you shall keep the feast to YHWH your God at the place he will choose, for YHWH your God will bless you in all your produce and in all the work of your hands, so that you will be altogether joyful.' <em>wᵉhāyîtā ʾak śāmēaḥ</em> (you shall be altogether joyful, only joyful) — the adverb <em>ʾak</em> (only, surely) intensifies: the seven days of Sukkot are to be marked by unqualified joy. This is the basis for Nehemiah's pronouncement when the Torah was read on Rosh Hashanah: 'the joy of the LORD is your strength' (Neh 8:10) — the covenant community's festival joy is not circumstantial but commanded and therefore sustainable.</p>",
    "16": "<p><strong>shalosh paamim bashanah yera'eh khal-zakhurkha et-pnei YHWH Eloheicha bamakom asher yivḥar</strong>: 'Three times a year all your males shall appear before YHWH your God at the place he will choose: at the Feast of Unleavened Bread, at the Feast of Weeks, and at the Feast of Booths.' The three-festival pilgrimage system (<em>šālôš pᵉʿāmîm baššānāh</em>) structures the agricultural-religious calendar into a triple annual encounter with YHWH. <em>yēraʾeh kol-zᵉkûrᵉkā ʾet-pᵉnê YHWH</em> (all your males shall appear before YHWH's face) — the idiom 'appear before the face' is the audience-before-the-king formula: the pilgrimage feast is an annual royal audience. <em>velo yera'eh et-pnei YHWH reiqam</em> (no one shall appear before YHWH empty-handed) — presence requires offering; the audience is never empty-handed.</p>",
    "17": "<p><strong>ish kemattnat yado kevirkhat YHWH Eloheicha asher natan-lakh</strong>: 'Every man shall give as he is able, in proportion to the blessing YHWH your God has given him.' The principle of proportional giving — <em>kᵉmattnat yāḏô</em> (according to the gift of his hand, i.e., his capacity) — is the foundation of Israel's festival economics. The measure is not equal contribution but equal sacrifice proportional to means: the rich man's obligation is greater because his capacity is greater. This principle governs the NT's theology of giving (2 Cor 8:12-13: 'if the readiness is there, it is acceptable according to what a person has, not according to what he does not have') and the assessment of the widow's mite (Mark 12:43-44: 'out of her poverty she put in everything she had').</p>",
    "18": "<p><strong>shofetim veshotrim titten lekha bekhol-she'areykha asher YHWH Eloheicha noten lekha lishvatekha</strong>: 'You shall appoint judges (<em>šōpᵉṭîm</em>) and officials (<em>šōṭᵉrîm</em>) throughout all your towns.' The administrative section (16:18-17:13) establishes the judicial infrastructure alongside the festival calendar, making the transition from cultic to civil law natural within the covenant framework. <em>šōpᵉṭîm</em> (judges) exercise decision-making authority; <em>šōṭᵉrîm</em> (officials) are enforcement officers or administrators. The town-by-town appointment ensures local access to justice: unlike Mesopotamian systems where courts were concentrated at major urban centers, Israel's covenant calls for justice at every town gate (<em>bᵉkol-šᵉʿāreykā</em>).</p>",
    "19": "<p><strong>lo-tatteh mishpat lo-takir panim velo-tikkaḥ shohad</strong>: 'Do not pervert justice (<em>mishpāṭ</em>); do not show favoritism (<em>pānîm</em>); do not accept a bribe (<em>šōḥaḏ</em>).' The three judicial prohibitions target the three primary corruption mechanisms: substantive injustice (warping the verdict), procedural partiality (recognizing faces = social bias), and financial corruption (bribery). <em>ki haššōḥaḏ yᵉʿawwēr ʿênê ḥăkāmîm wîsallēp diḇrê ṣaddîqîm</em> (for a bribe blinds the eyes of the wise and subverts the words of the righteous) — the two effects of bribery: cognitive blindness in the judge and rhetorical corruption of the verdict-speech. The prophetic tradition returns repeatedly to these three corruptions (Amos 5:12; Isa 1:23; Mic 3:11; Ezek 22:12).</p>",
    "21": "<p><strong>lo-tita lekha ashera kol-etz etzel mizbah YHWH Eloheicha</strong>: 'You shall not set up any wooden Asherah pole beside the altar of YHWH your God that you build.' The prohibition against the <em>ʾăšērāh</em> (wooden pole representing the Canaanite goddess Asherah) placed alongside YHWH's altar reflects the syncretistic tendency that repeatedly compromised Israelite worship. Placing an Asherah beside YHWH's altar was not outright rejection of YHWH but polytheistic accommodation — the very pattern the Deuteronomic reform under Josiah (2 Kgs 23:4-7,14-15) systematically eliminated. The prohibition is not about all trees but about trees erected as cult objects beside YHWH's altar.</p>",
    "22": "<p><strong>velo-taqim lekha mattzeva asher sane YHWH Eloheicha</strong>: 'And do not erect a sacred stone pillar (<em>maṣṣēḇāh</em>), for YHWH your God hates these.' The <em>maṣṣēḇāh</em> (standing stone, sacred pillar) is contextually prohibited: in earlier patriarchal narratives, Jacob erects <em>maṣṣēḇôt</em> without censure (Gen 28:18; 31:13,45; 35:14,20). Deuteronomy's prohibition targets not standing stones per se but their use in Canaanite religious practice: by the time of Deuteronomy's address, standing stones had been fully co-opted as Canaanite religious objects, making their use by Israel indistinguishable from Canaanite worship. Context determines whether an object is licit or illicit; the Canaanite cultural context has made the <em>maṣṣēḇāh</em> an idolatry-marker.</p>"
  },
  "17": {
    "1": "<p><strong>lo-tizbaḥ laYHWH Eloheicha shor vaseh asher yihyeh bo mum kol davar ra</strong>: 'You shall not sacrifice to YHWH your God an ox or a sheep that has a defect (<em>mûm</em>), any serious flaw (<em>kol dāḇār rāʿ</em>).' <em>kî tôʿăḇat YHWH Eloheycha hûʾ</em> (for it is an abomination (<em>tôʿēḇāh</em>) to YHWH your God) — defective sacrifice is not merely insufficient; it is abominable. Malachi 1:8 charges post-exilic Israel with precisely this: 'When you offer blind animals in sacrifice, is that not evil? When you offer those that are lame or sick, is that not evil?' The standard of unblemished sacrifice established here runs through Levitical law (Lev 22:20-25) to the typological fulfillment: Christ as the Passover lamb 'without blemish' (1 Pet 1:19).</p>",
    "2": "<p><strong>ki-yimmatze veqirbkha be'aḥad she'areykha ish o-isha asher ya'aseh et-hara</strong>: 'If there is found among you, in any of your towns, a man or a woman who does evil in the eyes of YHWH your God.' The case law on apostasy (vv. 2-7) concerns those who <em>ʿāḇar ʾet-bᵉrîtô</em> (transgressed his covenant) — the verb <em>ʿāḇar</em> (to cross over, transgress) applied to covenant violation uses the crossing-over metaphor: apostasy is the crossing of the covenant boundary into the outside territory of other gods. The structural principle is that covenant violation is a capital matter; the community's holiness requires the removal of the apostate, not out of cruelty but because the covenant is a living relationship that apostasy poisons.</p>",
    "3": "<p><strong>vayelekh vayya'avod elohim aḥerim vayishtaḥu lahem o lashemesh o layareaḥ</strong>: 'and has gone and served other gods and bowed down to them, or to the sun or the moon or any of the heavenly host.' The specific enumeration — other gods, sun, moon, heavenly host (<em>tzᵉḇāʾ haššāmayim</em>) — maps the full range of Canaanite-Mesopotamian celestial religion. Astral worship (sun, moon, stars) was the most cosmopolitan form of polytheism in the ancient world, practiced by Babylonians, Phoenicians, and Canaanites. <em>ʾăšer lōʾ-ṣiwwîṯî</em> (which I did not command) — the fundamental prohibition is not against any particular deity but against any divinity YHWH did not authorize: the covenant is exclusive, and any unauthorized deity-relationship is treachery.</p>",
    "4": "<p><strong>vehugad lekha veshama'ta veddarashta heitev vehinne emet nakhon hadavar</strong>: 'and you are informed and hear about it, then you shall investigate diligently (<em>darašta hêṭēḇ</em>); and if it is true and confirmed.' <em>dāraštā hêṭēḇ</em> (you shall investigate well, diligently) — the due-process requirement: before capital punishment is applied, thorough investigation is mandatory. The concern for evidentiary certainty reflects the covenant's justice-theology: YHWH's law requires both the punishment of evil and protection against wrongful punishment. The subsequent witnesses-requirement (v. 6) reinforces this: capital punishment requires multiple eyewitnesses, not suspicion or accusation alone.</p>",
    "5": "<p><strong>vehotzeta et-ha'ish hahu o et-ha'isha hahi el-she'arecha</strong>: 'then bring that man or woman to your town gate and stone them to death.' <em>el-šaʿăreykā</em> (to your town gate) — execution at the town gate (the community's public space of commerce, justice, and social life) makes the punishment a community act, not a private vendetta. The stoning itself distributes the act across the community: no single executioner bears the full weight; the community collectively enacts the covenant's defense of its own integrity. The witnesses act first (v. 7: <em>yaḏ hāʿēḏîm tihyeh-bô bārʾišônāh</em>), requiring those who testified to bear the primary responsibility for the death they testified to produce.</p>",
    "7": "<p><strong>yad ha'edim tihyeh-bo barishona lahamito veyad kol-ha'am baaharon</strong>: 'The witnesses shall be first to put him to death, and then all the people shall follow.' The witnesses-first-to-act requirement binds testimony to consequence: the witnesses cannot hide behind procedural distance from the execution. This dual role (testifier and first executioner) raises the cost of false witness dramatically — you must be prepared to kill the person you are accusing. <em>ûḇiʿartā hārāʿ miqqirbbekā</em> (so you shall purge the evil from your midst) — the <em>ûḇiʿartā hārāʿ</em> formula (purge/burn out the evil) appears seven times in Deuteronomy (13:5; 17:7,12; 19:19; 21:21; 22:21,24; 24:7) as the covenant's self-cleansing mechanism.</p>",
    "8": "<p><strong>ki yippale mimkha davar lamishpat bein-dam ledam bein-din ledin uvein-nega lanega</strong>: 'If a case arises that is too difficult for you, involving disputed homicide, disputed legal rights, or disputed assault.' The supreme court provision (vv. 8-13) addresses cases that exceed local judicial capacity. <em>yippālēʾ mimkā</em> (is too difficult/wonderful for you) — the same root (<em>pālāʾ</em>) as the divine wonders (Exod 3:20; 15:11); a case that is too wonderful for local courts is one that exceeds human capacity and requires higher authority. The three categories — <em>dam lᵉḏām</em> (blood-matter to blood-matter, homicide degrees), <em>dîn lᵉḏîn</em> (case to case, civil disputes), <em>nega lᵉnegaʿ</em> (wound to wound, assault degrees) — are the three principal case-types of ancient Israelite law.</p>",
    "9": "<p><strong>uvata el-hakohanim hallevi'im ve'el-hashofet asher yihyeh bayamim hahem</strong>: 'You shall go to the Levitical priests and to the judge who is serving at that time, and you shall consult them.' The supreme court consists of Levitical priests (for the theological-cultic dimension of difficult cases) and a civil judge (<em>šōpēṭ</em>). The combination of priestly and judicial authority reflects the covenant's unified legal structure: law is not divided into sacred and secular. <em>ʾăšer yihyeh bayyāmîm hāhēm</em> (who is serving in those days) — the judge's authority is tied to his appointment, not to personal charisma or genealogy; the institution (the office) has authority, not merely the individual.</p>",
    "10": "<p><strong>ve'asita al-pi hadavar asher yaggidu lekha min-hamakom hahu</strong>: 'You shall carry out the verdict they announce to you from that place YHWH will choose, and be careful to do according to all they instruct you.' The appellate verdict is binding. <em>vᵉšāmartā laʿăśôt kᵉḵōl ʾăšer yôrûkā</em> (be careful to do according to all they instruct you) — the verb <em>yāḏāh</em> (instruct) in Hiphil is the teaching-instruction form: the priests-and-judge's ruling is an act of Torah-instruction, not merely judicial decree. The supreme court's authority is derivative from Torah: they instruct (<em>yōrûkā</em>) what the Torah requires in the difficult case.</p>",
    "11": "<p><strong>al-pi hatorah asher yorukha ve'al-hamishpat asher yomru lekha ta'aseh</strong>: 'According to the instruction they give you and the verdict they pronounce, you shall act. Do not deviate from the verdict they announce to you, to the right or to the left.' <em>lo-tāsûr min-haddāḇār ʾăšer-yaggîḏû lᵉkā yāmîn ûśᵉmōl</em> (do not deviate to the right or the left) — the right-left directional metaphor for exact compliance with Torah-instruction appears elsewhere in Deuteronomy (5:32; 28:14) and Joshua (1:7; 23:6): exact adherence to YHWH's word requires neither addition (right deviation) nor subtraction (left deviation).</p>",
    "12": "<p><strong>veha'ish asher-ya'aseh bezadon leviltiy shemoa el-hakohen</strong>: 'The man who acts arrogantly by refusing to obey the priest who stands to minister before YHWH your God.' <em>bezāḏôn</em> (in arrogance, presumptuously) — the root <em>zûḏ/zāḏôn</em> (to be insolent, to act presumptuously) describes not merely disobedience but the posture of arrogance that places one's own judgment above authorized Torah-instruction. <em>ûmēt hāʾîš hahûʾ ûḇiʿartā hārāʿ miyyiśrāʾēl</em> (that man shall die; you shall purge the evil from Israel) — the death penalty for contempt of the supreme court is not about protecting judicial dignity but about preserving the covenant community's submission to YHWH's appointed instruction-authority.</p>",
    "13": "<p><strong>vekhol-ha'am yishme'u veyira'u velo yezidun od</strong>: 'And all the people shall hear and be afraid, and they will not act presumptuously again.' <em>wᵉyirāʾû wᵉlōʾ yᵉzîḏûn ʿôḏ</em> (will fear and not act presumptuously again) — the public deterrence function of exemplary punishment is explicitly stated. Deuteronomy's criminal law consistently has this dual function: removing the offender (<em>bîʿartā hārāʿ</em>) and deterring others through fear. This deterrence-through-public-knowledge pattern recurs in Acts 5:11 after Ananias and Sapphira's deaths: 'great fear came upon the whole church and upon all who heard of these things.'</p>",
    "14": "<p><strong>ki-tavo el-ha'aretz asher YHWH Eloheicha noten lakh vyrishtah veyashavta bah</strong>: 'When you come to the land YHWH your God is giving you and have taken possession and settled in it, and you say, Let me set a king over me like all the nations around me.' The law of the king (vv. 14-20) is introduced as a prediction of Israel's future desire: <em>śîmāh ʿālay melek</em> (set a king over me). The permissive-yet-regulated character of the royal law is distinctive: YHWH does not command a king but permits one with strict conditions. The phrase <em>kᵉkol-haggôyim ʾăšer sᵉḇîḇōtay</em> (like all the nations around me) — the explicit comparison to surrounding nations identifies the motivation as conformist: Israel wants a king not because of covenant need but to match international political norms. Samuel's rebuke in 1 Sam 8 draws directly on this passage.</p>",
    "15": "<p><strong>som tasim alekha melekh asher yivḥar YHWH Eloheicha bo</strong>: 'you may set a king over you — but he must be the one YHWH your God chooses.' <em>śôm tāśîm ʿāleykā melek</em> (you shall certainly set a king over you) — the doubled imperative is permissive-mandatory: if Israel will have a king, then YHWH's selection process applies. <em>mittqerev aḥeykha</em> (from among your brothers) — the king must be a fellow Israelite, not a foreign appointee. The YHWH-chooses clause (repeated in 1 Sam 16:1: 'I have provided for myself a king among his sons') frames the entire monarchy under divine selection rather than human election or hereditary right. The Northern Kingdom's repeated violations of this principle (1 Kgs 12:16-20; Hos 8:4) reflect the ongoing tension between the YHWH-chooses model and human political reality.</p>",
    "16": "<p><strong>raq lo-yarbeh-lo susim velo-yashiv et-ha'am mitzraymah</strong>: 'But he must not acquire many horses for himself or send people back to Egypt to get more horses.' The three anti-accumulation prohibitions — no horses, no wives, no silver/gold (vv. 16-17) — are the Law of the King's core restrictions. <em>lo-yarbeh-lo susim</em> (he shall not multiply horses for himself) — the reflexive <em>lo</em> (for himself) makes the prohibition self-interested accumulation, not military capacity per se. The Egypt-horse trade is explicitly prohibited: <em>vᵉlōʾ yāšîḇ ʾet-hāʿām Miṣraymāh</em> (he shall not return the people to Egypt) — the theological rationale is stated: 'The LORD has said to you, You shall never return that way again.' The Exodus is irreversible; any policy that recreates dependence on Egypt reverses the redemption.</p>",
    "17": "<p><strong>velo yarbeh-lo nashim velo yasur levavo vekhesef vezahav lo yarbeh-lo meod</strong>: 'He must not take many wives for himself, so his heart is not led astray, nor shall he accumulate excessive silver and gold.' The three prohibitions are narrated precisely in Solomon's failure: he multiplied horses (1 Kgs 10:26-29), multiplied wives (1 Kgs 11:1-8: 700 wives and 300 concubines), and accumulated silver and gold (1 Kgs 10:14-22). <em>wᵉlōʾ yāsûr lᵉḇāḇô</em> (his heart shall not turn aside) — the heart-turning metaphor for covenant infidelity: the wives 'turned his heart after other gods' (1 Kgs 11:4). Deuteronomy's royal law is structured as a prophylactic against the very failures that the most celebrated king would exemplify — a programmatic critique embedded in the law before the fact.</p>",
    "19": "<p><strong>vehayeta immo veqara vo kol-yemei ḥayav lema'an yilmad leyira et-YHWH Elohav</strong>: 'It shall be with him, and he shall read in it all the days of his life, that he may learn to fear YHWH his God.' The king's Torah-reading is for formation, not merely information: <em>lᵉmaʿan yilmad lᵉyārᵉʾāh ʾet-YHWH Elohāyw</em> (that he may learn to fear YHWH his God). The fear of YHWH (<em>yirʾat YHWH</em>) is the foundational disposition of covenant faithfulness — the comprehensive awe-and-trust that produces obedience. <em>lišmōr ʾet-kol-diḇrê hattôrāh hazzōʾt wᵉʾet-haḥuqqîm hāʾēlleh</em> (keeping all the words of this Torah and these statutes) — Torah-reading produces Torah-observance, but the causal sequence is formation through immersion (<em>kol-yemê ḥayyāyw</em>, all the days of his life): daily reading, lifelong formation.</p>",
    "20": "<p><strong>leviltiy rum-levavo me'eḥav uviltiy sur min-hamitzvah yamim usmol</strong>: 'so that his heart will not be lifted up above his brothers, and so that he will not turn from the commandment to the right or to the left.' <em>lᵉḇiltî rûm-lᵉḇāḇô mēʾeḥāyw</em> (that his heart not be lifted above his brothers) — the king's danger is heart-elevation: social and political superiority translating into covenantal arrogance, the assumption that his role exempts him from the covenant demands binding on all Israelites. <em>lᵉmaʿan yaʾărîk yāmîm ʿal-mamlaḵtô hûʾ ûḇānāyw bᵉqereb yiśrāʾēl</em> (so that he may lengthen his days in his kingdom, he and his children, in the midst of Israel) — the long-dynasty promise is conditional on Torah-humility. The NT's servant-kingship theology (Mark 10:42-45: 'the greatest among you shall be your servant') fulfills this Deuteronomic vision of the king whose authority is expressed through covenant obedience and self-lowering, not elevation above the covenant community.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'deuteronomy')
    merge_comm(existing, DEUT)
    save_comm('mkt-original', 'deuteronomy', existing)
    total = sum(len(v) for v in DEUT.values())
    print(f'Deuteronomy 14-17 original fill: {total} verses written.')

if __name__ == '__main__':
    main()
